<?php
namespace Vendor\CustomConfig\Model\Config\Backend;

use Magento\Framework\Model\Context;
use Magento\Framework\Registry;
use Vnecoms\VendorsConfig\Model\ResourceModel\Config as ConfigResource;
use Vnecoms\VendorsConfig\Model\ResourceModel\Config\Collection as ConfigResourceCollection;
use Vnecoms\VendorsConfig\Helper\Data as VnecomsConfigHelper;
use Magento\Framework\App\Config\ScopeConfigInterface;
use Magento\Framework\App\Cache\TypeListInterface;
use Magento\MediaStorage\Model\File\UploaderFactory;
use Magento\Config\Model\Config\Backend\File\RequestData\RequestDataInterface;
use Magento\Framework\Serialize\Serializer\Serialize;
use Magento\Framework\Filesystem;
use Vnecoms\Vendors\Model\Session as VendorSession;
use Magento\Framework\App\ResourceConnection;

class VendorLogo extends \Vnecoms\VendorsConfig\Model\Config\Backend\File
{
    protected $vendorSession;
    protected $resourceConnection;
    protected $_logger;

    // Your logo attribute_id in ves_vendor_entity_varchar
    protected $attributeId = 187;

    public function __construct(
        Context $context,
        Registry $registry,
        ConfigResource $resource = null,
        ConfigResourceCollection $resourceCollection = null,
        VnecomsConfigHelper $configHelper,
        ScopeConfigInterface $config,
        TypeListInterface $cacheTypeList,
        UploaderFactory $uploaderFactory,
        RequestDataInterface $requestData,
        Serialize $serialize,
        Filesystem $filesystem,
        VendorSession $vendorSession,
        ResourceConnection $resourceConnection,
        \Psr\Log\LoggerInterface $logger,
        array $data = []
    ) {
        $this->vendorSession = $vendorSession;
        $this->resourceConnection = $resourceConnection;
        $this->_logger = $logger;

        parent::__construct(
            $context,
            $registry,
            $resource,
            $resourceCollection,
            $configHelper,
            $config,
            $cacheTypeList,
            $uploaderFactory,
            $requestData,
            $serialize,
            $filesystem,
            $data
        );
        file_put_contents(BP . '/var/log/config_debug.log', "✅ vendor logo Constructor called\n", FILE_APPEND);
    }

public function afterSave()
{
    $writer = new \Zend_Log_Writer_Stream(BP . '/var/log/config_debug.log');
    $logger = new \Zend_Log();
    $logger->addWriter($writer);
    $logger->info('✅ afterSave() called for Vendor Logo');

    $vendorId = $this->getVendorId();
    $attributeId = 187;

    if (!$vendorId) {
        $logger->info("⚠️ Vendor ID missing, skipping logo save.");
        return parent::afterSave();
    }

    $value = $this->getValue();

    // Handle cases when user deletes or uploads a new logo
    if (is_array($value)) {
        if (!empty($value['delete'])) {
            $value = ''; // deleted
        } elseif (isset($value['value'])) {
            $value = $value['value']; // relative path generated by uploader
        } else {
            $value = '';
        }
    }

    if (!$value) {
        $logger->info("⚠️ Empty logo value, skipping update.");
        return parent::afterSave();
    }

    // ✅ Ensure the value contains the correct relative path from media root
    if (strpos($value, 'ves_vendors/attribute/upload_logo/') === false) {
        $value = 'ves_vendors/attribute/upload_logo/' . ltrim($value, '/');
    }

    $logger->info("🟢 Final logo value to save: " . $value);

    $connection = $this->resourceConnection->getConnection();
    $tableName = $this->resourceConnection->getTableName('ves_vendor_entity_varchar');

    // Check if record already exists
    $select = $connection->select()
        ->from($tableName, ['value_id'])
        ->where('entity_id = ?', $vendorId)
        ->where('attribute_id = ?', $attributeId);

    $exists = $connection->fetchOne($select);

    if ($exists) {
        $connection->update(
            $tableName,
            ['value' => $value],
            ['value_id = ?' => $exists]
        );
        $logger->info("🟢 Updated logo for Vendor ID: {$vendorId}");
    } else {
        $connection->insert(
            $tableName,
            [
                'entity_id' => $vendorId,
                'attribute_id' => $attributeId,
                'value' => $value
            ]
        );
        $logger->info("🟢 Inserted logo for Vendor ID: {$vendorId}");
    }

    return parent::afterSave();
}
public function afterLoad()
    {
        $vendorId = $this->vendorSession && $this->vendorSession->getVendor()
            ? $this->vendorSession->getVendor()->getId()
            : null;

        if (!$vendorId) {
            $this->_logger->info("Vendor ID missing in afterLoad() for logo.");
            return parent::afterLoad();
        }

        $connection = $this->resourceConnection->getConnection();
        $table = $this->resourceConnection->getTableName('ves_vendor_entity_varchar');

        $select = $connection->select()
            ->from($table, ['value'])
            ->where('entity_id = ?', $vendorId)
            ->where('attribute_id = ?', $this->attributeId)
            ->limit(1);

        $value = $connection->fetchOne($select);

        if ($value !== false && $value !== null) {
            // Correctly set the relative path from DB
            $this->setValue($value);
            $this->_logger->info("Loaded vendor logo for vendor ID: {$vendorId}");
        }

        return parent::afterLoad();
    }
}
